function part57CleanText(value, max = 120) {
  return String(value ?? "").trim().replace(/[<>]/g, "").slice(0, max);
}

function part57Money(value) {
  const num = Number(value || 0);
  return Number.isFinite(num) ? Math.max(0, Math.round(num)) : 0;
}

