function normalizePart94Role(role) {
  const r = String(role || "student").toLowerCase().trim().replace(/\s+/g, "_");
  if (["owner", "instituteowner", "institute_owner"].includes(r)) return "institute_owner";
  if (["branchmanager", "branch_manager"].includes(r)) return "branch_manager";
  if (["receptionist", "counsellor", "receptionist_counsellor"].includes(r)) return "receptionist_counsellor";
  return r;
}

function part94AccessCheck({ role, instituteId, branchId, batchId, teacherId, studentId, parentId, roomId }) {
  const normalizedRole = normalizePart94Role(role);
  const rule = part94RoleRules.find((r) => r.role === normalizedRole) || {
    role: normalizedRole,
    allowed: false,
    scope: "Unknown or unsupported role.",
    canHost: false,
    canMonitor: false
  };
  const hasInstituteId = Boolean(String(instituteId || "").trim());
  const allowed = Boolean(rule.allowed && hasInstituteId && normalizedRole !== "naxora_super_admin");
  const teacherAssigned = normalizedRole !== "teacher" || Boolean(String(teacherId || "").trim() || String(batchId || "").trim());
  const studentOwnClass = normalizedRole !== "student" || Boolean(String(studentId || "").trim() || String(batchId || "").trim());
  const parentLinkedOnly = normalizedRole !== "parent" || Boolean(String(parentId || "").trim() || String(studentId || "").trim());

  const scopedAllowed = allowed && teacherAssigned && studentOwnClass && parentLinkedOnly;

  return {
    role: normalizedRole,
    instituteId: instituteId || null,
    branchId: branchId || null,
    batchId: batchId || null,
    teacherId: teacherId || null,
    studentId: studentId || null,
    parentId: parentId || null,
    roomId: roomId || null,
    allowed: scopedAllowed,
    canHost: Boolean(rule.canHost && scopedAllowed),
    canMonitor: Boolean(rule.canMonitor && scopedAllowed),
    viewOnly: Boolean(rule.viewOnly),
    demoOnly: Boolean(rule.demoOnly),
    scope: rule.scope,
    reason: !hasInstituteId
      ? "Institute ID missing."
      : !rule.allowed
        ? rule.scope
        : !teacherAssigned
          ? "Teacher live classroom access requires assigned teacherId or batchId."
          : !studentOwnClass
            ? "Student can join own scheduled class only; studentId or batchId required."
            : !parentLinkedOnly
              ? "Parent can view linked child status only; parentId/studentId required."
              : "Native live classroom foundation access allowed.",
    requiresLogin: true,
    requiresInstituteId: true,
    requiresAssignedScope: ["teacher", "student", "parent"].includes(normalizedRole),
    confirmationRequiredFor: ["start_live_class", "end_live_class", "admit_participant", "remove_participant", "record_class"],
    ownerVerificationRequiredFor: ["recording_export", "delete_recording", "bulk_remove", "privacy_change"]
  };
}

function part94ParseCommand(text = "", body = {}) {
  const input = String(text || body.command || body.q || "").trim();
  const classMatch = input.match(/class\s*([0-9]{1,2})/i);
  const subjectMatch = input.match(/\b(maths|math|science|english|physics|chemistry|biology|commerce|accounts|sst|social science)\b/i);
  const intent = /device|camera|mic|microphone|speaker/i.test(input) ? "device_check"
    : /network|internet|speed|latency/i.test(input) ? "network_check"
      : /join|student/i.test(input) ? "join_preview"
        : /start|launch|live class|classroom/i.test(input) ? "launch_preview"
          : /status|room/i.test(input) ? "room_status"
            : "help";
  return {
    intent,
    className: body.className || (classMatch ? `Class ${classMatch[1]}` : null),
    subject: body.subject || (subjectMatch ? subjectMatch[1].toLowerCase().replace("math", "maths").replace("social science", "sst") : null),
    roomId: body.roomId || (/science/i.test(input) ? "LIVE-DEMO-SCIENCE" : "LIVE-DEMO-CLASS10-MATHS"),
    rawCommand: input
  };
}

function part94DeviceReadiness(userAgent = "") {
  return {
    previewOnly: true,
    browserAPIs: {
      mediaDevices: true,
      getUserMedia: true,
      webRTC: true,
      speechSynthesis: true,
      speechRecognition: true
    },
    checks: [
      { key: "camera", status: "needs_browser_permission", message: "Camera permission browser popup se allow karni hogi." },
      { key: "microphone", status: "needs_browser_permission", message: "Microphone permission browser popup se allow karni hogi." },
      { key: "speaker", status: "browser_output", message: "Speaker output device browser/OS se control hoga." },
      { key: "screen_share", status: "part95_pending", message: "Screen sharing Part 95 me production foundation ke saath aayega." },
      { key: "recording", status: "part97_pending", message: "Recording and automatic attendance Part 97 me aayega." }
    ],
    recommendation: "Chrome/Edge latest version best. Class se pehle camera/mic test karna zaroori hai.",
    userAgent: userAgent || "not_provided"
  };
}

function part94NetworkReadiness() {
  return {
    previewOnly: true,
    recommendedMinimum: {
      teacherUpload: "3 Mbps+",
      teacherDownload: "5 Mbps+",
      studentDownload: "2 Mbps+",
      latency: "Under 150ms preferred"
    },
    qualityLevels: [
      { level: "good", condition: "Stable Wi-Fi/4G/5G and low latency" },
      { level: "medium", condition: "Video may reduce quality automatically" },
      { level: "low", condition: "Audio-first mode recommended" }
    ],
    note: "Real WebRTC bandwidth scoring will be added in later live classroom parts."
  };
}

function part94FindRoom({ roomId, batchId, subject }) {
  const id = String(roomId || "").trim();
  if (id) {
    const match = part94DemoRooms.find((r) => r.roomId === id);
    if (match) return match;
  }
  const b = String(batchId || "").trim();
  if (b) {
    const match = part94DemoRooms.find((r) => r.batchId === b);
    if (match) return match;
  }
  const s = String(subject || "").toLowerCase();
  if (s) {
    const match = part94DemoRooms.find((r) => r.subject.toLowerCase().includes(s));
    if (match) return match;
  }
  return part94DemoRooms[0];
}

function part94ParticipantPolicy(access = {}) {
  return {
    previewOnly: true,
    role: access.role,
    permissions: {
      canJoin: Boolean(access.allowed && !access.viewOnly),
      canHost: Boolean(access.canHost),
      canMonitor: Boolean(access.canMonitor),
      canUseMic: access.role === "teacher" || access.role === "student",
      canUseCamera: access.role === "teacher" || access.role === "student",
      canRaiseHand: access.role === "student",
      canChat: ["teacher", "student"].includes(access.role),
      canAdmitParticipants: access.role === "teacher",
      canRemoveParticipants: access.role === "teacher",
      canRecord: false,
      canScreenShare: false
    },
    pendingParts: {
      screenShareAndWhiteboard: "Part 95",
      liveChatPollsHandRaise: "Part 96",
      recordingAttendance: "Part 97"
    },
    safety: "Live classroom actions require assigned scope and confirmation for sensitive actions."
  };
}

function part94JoinTokenPreview(access = {}, room = {}) {
  const role = access.role || "student";
  return {
    previewOnly: true,
    tokenId: `JOIN-PREVIEW-${role.toUpperCase()}-${Date.now()}`,
    roomId: room.roomId,
    role,
    expiresInPreview: "15 minutes",
    finalTokenRequiresAuth: true,
    allowed: Boolean(access.allowed && !access.viewOnly),
    safety: "Token is a preview only. Production join token signing will be added with real session storage."
  };
}

function part94RoomPreview({ command, role, instituteId, branchId, batchId, teacherId, studentId, parentId, body = {} }) {
  const parsed = part94ParseCommand(command, body);
  const access = part94AccessCheck({
    role,
    instituteId,
    branchId,
    batchId: body.batchId || batchId,
    teacherId: body.teacherId || teacherId,
    studentId: body.studentId || studentId,
    parentId: body.parentId || parentId,
    roomId: parsed.roomId
  });
  const room = part94FindRoom({ roomId: parsed.roomId, batchId: body.batchId || batchId, subject: parsed.subject });
  const deviceReadiness = part94DeviceReadiness(body.userAgent || "");
  const networkReadiness = part94NetworkReadiness();
  const participantPolicy = part94ParticipantPolicy(access);
  const joinTokenPreview = part94JoinTokenPreview(access, room);

  let replyText = "";
  let nextAction = "none";
  if (!access.allowed) {
    replyText = "Is role/scope ko native live classroom access nahi hai.";
    nextAction = "blocked";
  } else if (access.viewOnly) {
    replyText = "Parent view-only mode me linked child ki class status dekh sakta hai. Classroom join institute policy ke bina allowed nahi.";
    nextAction = "show_child_class_status";
  } else if (parsed.intent === "device_check") {
    replyText = "Device readiness preview ready hai. Camera aur mic permission browser se allow karni hogi.";
    nextAction = "show_device_readiness";
  } else if (parsed.intent === "network_check") {
    replyText = "Network readiness guidance ready hai. Stable internet live class ke liye zaroori hai.";
    nextAction = "show_network_readiness";
  } else if (parsed.intent === "join_preview") {
    replyText = `${room.title} ke liye join preview ready hai. Real join token auth ke baad generate hoga.`;
    nextAction = "show_join_preview";
  } else {
    replyText = `${room.title} native live classroom foundation preview ready hai. Start live class confirmation ke bina nahi hoga.`;
    nextAction = access.canHost ? "show_launch_preview" : "show_room_preview";
  }

  return {
    access,
    parsed,
    room,
    deviceReadiness,
    networkReadiness,
    participantPolicy,
    joinTokenPreview,
    launchPreview: {
      previewOnly: true,
      roomId: room.roomId,
      title: room.title,
      teacherId: room.teacherId,
      batchId: room.batchId,
      schedule: room.schedule,
      canLaunchNow: Boolean(access.canHost),
      confirmationRequired: true,
      productionSignallingPending: true,
      note: "Production WebRTC signalling, whiteboard, screen share, chat and recording will be added across Parts 95-97."
    },
    replyText,
    spokenSafeSummary: replyText,
    privateScreenFirst: true,
    nextAction,
    confirmationRequiredFor: ["start_live_class", "end_live_class", "admit_participant", "remove_participant", "record_class"],
    ownerVerificationRequiredFor: ["recording_export", "delete_recording", "bulk_remove", "privacy_change"],
    auditLog: {
      event: "part94_native_live_classroom_foundation",
      role: access.role,
      roomId: room.roomId,
      intent: parsed.intent,
      createdAt: new Date().toISOString()
    }
  };
}

