function normalizePart96Role(role) {
  const r = String(role || "student").toLowerCase().trim().replace(/\s+/g, "_");
  if (["owner", "instituteowner", "institute_owner"].includes(r)) return "institute_owner";
  if (["branchmanager", "branch_manager"].includes(r)) return "branch_manager";
  if (["receptionist", "counsellor", "receptionist_counsellor"].includes(r)) return "receptionist_counsellor";
  return r;
}

function part96AccessCheck({ role, instituteId, branchId, batchId, teacherId, studentId, parentId, sessionId }) {
  const normalizedRole = normalizePart96Role(role);
  const rule = part96RoleRules.find((r) => r.role === normalizedRole) || {
    role: normalizedRole,
    allowed: false,
    scope: "Unknown or unsupported role.",
    canModerate: false,
    canCreatePoll: false,
    canChat: false,
    canVote: false,
    canRaiseHand: false,
    canMonitor: false
  };
  const hasInstituteId = Boolean(String(instituteId || "").trim());
  const teacherAssigned = normalizedRole !== "teacher" || Boolean(String(teacherId || "").trim() || String(batchId || "").trim());
  const studentOwnClass = normalizedRole !== "student" || Boolean(String(studentId || "").trim() || String(batchId || "").trim());
  const parentLinkedOnly = normalizedRole !== "parent" || Boolean(String(parentId || "").trim() || String(studentId || "").trim());
  const allowed = Boolean(rule.allowed && hasInstituteId && teacherAssigned && studentOwnClass && parentLinkedOnly && normalizedRole !== "naxora_super_admin");
  return {
    role: normalizedRole,
    instituteId: instituteId || null,
    branchId: branchId || null,
    batchId: batchId || null,
    teacherId: teacherId || null,
    studentId: studentId || null,
    parentId: parentId || null,
    sessionId: sessionId || part96DemoSession.sessionId,
    allowed,
    canModerate: Boolean(rule.canModerate && allowed),
    canCreatePoll: Boolean(rule.canCreatePoll && allowed),
    canChat: Boolean(rule.canChat && allowed),
    canVote: Boolean(rule.canVote && allowed),
    canRaiseHand: Boolean(rule.canRaiseHand && allowed),
    canMonitor: Boolean(rule.canMonitor && allowed),
    viewOnly: Boolean(rule.viewOnly),
    demoOnly: Boolean(rule.demoOnly),
    scope: rule.scope,
    reason: !hasInstituteId
      ? "Institute ID missing."
      : !rule.allowed
        ? rule.scope
        : !teacherAssigned
          ? "Teacher classroom interaction requires assigned teacherId or batchId."
          : !studentOwnClass
            ? "Student can interact in own scheduled class only."
            : !parentLinkedOnly
              ? "Parent can view linked child status only."
              : "Classroom interaction access allowed.",
    requiresLogin: true,
    requiresInstituteId: true,
    confirmationRequiredFor: ["delete_chat", "mute_student", "close_poll", "remove_hand_raise", "disable_chat"],
    ownerVerificationRequiredFor: ["export_chat", "delete_interaction_logs", "privacy_change"]
  };
}

function part96ParseCommand(text = "", body = {}) {
  const input = String(text || body.command || body.q || "").trim();
  const intent = /poll|quiz|vote/i.test(input) ? "poll"
    : /hand|raise|doubt/i.test(input) ? "hand_raise"
      : /chat|message|doubt/i.test(input) ? "chat"
        : /moderate|mute|delete|block/i.test(input) ? "moderation"
          : /status|summary|queue/i.test(input) ? "status"
            : "help";
  const messageMatch = input.match(/(?:message|chat|bolo|send)\s*[:\-]?\s*(.+)$/i);
  return {
    intent,
    sessionId: body.sessionId || part96DemoSession.sessionId,
    messageText: body.messageText || messageMatch?.[1] || (intent === "chat" ? input : null),
    pollQuestion: body.pollQuestion || (/poll|quiz/i.test(input) ? "Is topic clear hai?" : null),
    rawCommand: input
  };
}

function part96ModerateText(text = "") {
  const value = String(text || "").trim();
  const blockedPatterns = [/spam/i, /abuse/i, /badword/i, /personal number/i, /password/i];
  const blocked = blockedPatterns.some((p) => p.test(value));
  return {
    allowed: Boolean(value && value.length <= part96DemoSession.maxChatLength && !blocked),
    reason: !value
      ? "Message empty."
      : value.length > part96DemoSession.maxChatLength
        ? "Message too long."
        : blocked
          ? "Message blocked by classroom safety policy."
          : "Message allowed in preview.",
    maxLength: part96DemoSession.maxChatLength
  };
}

function part96ChatPolicy(access = {}) {
  return {
    previewOnly: true,
    chatEnabled: part96DemoSession.chatEnabled,
    maxChatLength: part96DemoSession.maxChatLength,
    role: access.role,
    canChat: access.canChat,
    canModerate: access.canModerate,
    teacherCanDelete: access.role === "teacher",
    studentCanDeleteOwnPreview: access.role === "student",
    parentViewOnly: access.viewOnly,
    rules: [
      "Chat is classroom-only.",
      "Teacher moderation first.",
      "No sharing passwords or sensitive personal data.",
      "Final deletion/export requires authorised confirmation.",
      "Production realtime socket persistence will be connected later."
    ]
  };
}

function part96SendMessagePreview({ access, text, senderName }) {
  const moderation = part96ModerateText(text);
  return {
    previewOnly: true,
    canSend: Boolean(access.canChat && moderation.allowed),
    moderation,
    message: {
      messageId: `MSG-PREVIEW-${Date.now()}`,
      senderRole: access.role,
      senderName: senderName || access.role,
      text: String(text || "").trim(),
      status: access.role === "student" ? "teacher_moderated_preview" : "visible_preview",
      createdAt: new Date().toISOString()
    },
    finalPersistencePending: true
  };
}

function part96PollCreatePreview({ access, question, options }) {
  const safeOptions = Array.isArray(options) && options.length >= 2 ? options.slice(0, 6) : ["Yes", "No", "Need explanation"];
  return {
    previewOnly: true,
    canCreate: Boolean(access.canCreatePoll),
    poll: {
      pollId: `POLL-PREVIEW-${Date.now()}`,
      question: question || "Is topic clear hai?",
      options: safeOptions,
      status: "open_preview",
      createdByRole: access.role,
      votesPreview: Object.fromEntries(safeOptions.map((o) => [o, 0]))
    },
    confirmationRequiredToClose: true,
    finalPersistencePending: true
  };
}

function part96VotePreview({ access, pollId, option }) {
  return {
    previewOnly: true,
    canVote: Boolean(access.canVote),
    pollId: pollId || "POLL-DEMO-001",
    selectedOption: option || "b² - 4ac",
    status: access.canVote ? "vote_preview_ready" : "vote_not_allowed",
    finalPersistencePending: true
  };
}

function part96HandRaisePreview({ access, studentName, reason }) {
  return {
    previewOnly: true,
    canRaiseHand: Boolean(access.canRaiseHand),
    request: {
      requestId: `HR-PREVIEW-${Date.now()}`,
      studentId: access.studentId || "STU-PREVIEW",
      studentName: studentName || "Student",
      reason: reason || "Doubt / need help",
      status: access.canRaiseHand ? "waiting_preview" : "not_allowed",
      raisedAt: new Date().toISOString()
    },
    teacherQueueVisible: true,
    finalPersistencePending: true
  };
}

function part96ModerationActionPreview({ access, action, targetId }) {
  return {
    previewOnly: true,
    canModerate: Boolean(access.canModerate),
    action: action || "lower_hand_raise",
    targetId: targetId || "HR-DEMO-001",
    confirmationRequired: ["delete_chat", "mute_student", "disable_chat"].includes(action),
    result: access.canModerate ? "moderation_action_preview_ready" : "moderation_not_allowed",
    finalPersistencePending: true
  };
}

function part96BuildInteraction({ command, role, instituteId, branchId, batchId, teacherId, studentId, parentId, body = {} }) {
  const parsed = part96ParseCommand(command, body);
  const access = part96AccessCheck({
    role,
    instituteId,
    branchId,
    batchId: body.batchId || batchId,
    teacherId: body.teacherId || teacherId,
    studentId: body.studentId || studentId,
    parentId: body.parentId || parentId,
    sessionId: parsed.sessionId
  });
  const chatPolicy = part96ChatPolicy(access);
  const chatPreview = part96SendMessagePreview({ access, text: parsed.messageText || "Doubt clear nahi hua.", senderName: body.senderName });
  const pollPreview = part96PollCreatePreview({ access, question: parsed.pollQuestion || body.pollQuestion, options: body.options });
  const votePreview = part96VotePreview({ access, pollId: body.pollId, option: body.option });
  const handRaisePreview = part96HandRaisePreview({ access, studentName: body.studentName, reason: body.reason });
  const moderationPreview = part96ModerationActionPreview({ access, action: body.action || "lower_hand_raise", targetId: body.targetId });

  let replyText = "";
  let nextAction = "none";
  if (!access.allowed) {
    replyText = "Is role/scope ko live chat, polls aur hand raise access nahi hai.";
    nextAction = "blocked";
  } else if (access.viewOnly) {
    replyText = "Parent view-only mode me classroom interaction summary dekh sakta hai. Chat, vote aur hand raise allowed nahi.";
    nextAction = "show_view_only_status";
  } else if (parsed.intent === "poll") {
    replyText = access.canCreatePoll
      ? "Poll create preview ready hai. Real-time votes production socket connection ke baad save honge."
      : access.canVote
        ? "Student vote preview ready hai. Final vote realtime persistence ke baad save hoga."
        : "Is role ko poll create/vote permission nahi hai.";
    nextAction = access.canCreatePoll ? "show_poll_create_preview" : "show_vote_preview";
  } else if (parsed.intent === "hand_raise") {
    replyText = access.canRaiseHand
      ? "Hand raise preview ready hai. Teacher queue me request dikhegi."
      : access.canModerate
        ? "Teacher hand raise queue preview ready hai."
        : "Is role ko hand raise action allowed nahi.";
    nextAction = access.canRaiseHand ? "show_hand_raise_preview" : "show_hand_raise_queue";
  } else if (parsed.intent === "chat") {
    replyText = access.canChat
      ? "Chat message preview ready hai. Teacher moderation policy apply hogi."
      : "Is role ko classroom chat permission nahi hai.";
    nextAction = "show_chat_preview";
  } else {
    replyText = "Live chat, polls aur hand raise classroom interaction preview ready hai.";
    nextAction = "show_interaction_summary";
  }

  return {
    access,
    parsed,
    session: part96DemoSession,
    messagesPreview: part96DemoMessages,
    pollsPreview: part96DemoPolls,
    handRaiseQueuePreview: part96HandRaiseQueue,
    chatPolicy,
    chatPreview,
    pollPreview,
    votePreview,
    handRaisePreview,
    moderationPreview,
    replyText,
    spokenSafeSummary: replyText,
    privateScreenFirst: true,
    nextAction,
    socketReadyFoundation: true,
    productionRealtimePending: true,
    confirmationRequiredFor: ["delete_chat", "mute_student", "close_poll", "remove_hand_raise", "disable_chat"],
    ownerVerificationRequiredFor: ["export_chat", "delete_interaction_logs", "privacy_change"],
    auditLog: {
      event: "part96_live_chat_polls_hand_raise",
      role: access.role,
      intent: parsed.intent,
      sessionId: parsed.sessionId,
      createdAt: new Date().toISOString()
    }
  };
}

